const sess = db.prepare(\"SELECT id, content FROM books_animator_sessions\").all();
const roles = { reader: [], analyst: [], 'spec-writer': [] };
for (const s of sess) {
  const c = JSON.parse(s.content);
  const e = c.metadata?.engineId;
  if (roles[e]) roles[e].push(s.id);
}
for (const [eng, sids] of Object.entries(roles)) {
  const counts = {};
  for (const sid of sids) {
    const row = db.prepare('SELECT content FROM books_animator_transcripts WHERE id=?').get(sid);
    if (!row) continue;
    const t = JSON.parse(row.content);
    for (const m of t.messages || []) {
      if (m.type !== 'assistant') continue;
      for (const block of m.message?.content || []) {
        if (block.type === 'tool_use') counts[block.name] = (counts[block.name]||0)+1;
      }
    }
  }
  console.log(eng, 'sessions='+sids.length, counts);
}
