#!/bin/bash
# Scan all plugin tool definitions, extracting name, permission, callableBy.
cd /workspace/nexus/packages/plugins
for f in $(grep -rln "tool({" . --include="*.ts" 2>/dev/null | grep -v test | grep -v dist); do
  # Extract plugin name from path
  plugin=$(echo "$f" | sed -E 's|^\./([^/]+)/.*|\1|')
  # Use awk to find each tool() block and pull name/permission/callableBy
  awk -v PL="$plugin" -v FN="$f" '
    BEGIN { depth=0; in_tool=0; name=""; perm=""; cb=""; }
    /tool\(\{/ { in_tool=1; depth=1; name=""; perm=""; cb=""; next }
    in_tool {
      # Track brace depth crudely
      n = gsub(/\{/, "&")
      m = gsub(/\}/, "&")
      depth += n - m
      if (match($0, /name:[[:space:]]*["'"'"']([^"'"'"']+)["'"'"']/, a)) name=a[1]
      if (match($0, /permission:[[:space:]]*["'"'"']([^"'"'"']+)["'"'"']/, a)) perm=a[1]
      if (match($0, /callableBy:[[:space:]]*(\[[^\]]*\]|["'"'"'][^"'"'"']+["'"'"'])/, a)) cb=a[1]
      if (depth <= 0) {
        if (name) printf("%s\t%s\t%s\t%s\t%s\n", PL, name, (perm?perm:"-"), (cb?cb:"-"), FN)
        in_tool=0
      }
    }
  ' "$f"
done | sort

